"use client";

import {
  createContext,
  createElement,
  useContext,
  type ReactNode,
} from "react";
import type {
  WalletEip712Payload,
  WalletTxPayload,
} from "@aomi-labs/react";
import type { AccountIdentity } from "./account-identity";

// =============================================================================
// WalletAdapter type
// =============================================================================

export type WalletAdapter = {
  identity: AccountIdentity;
  isReady: boolean;
  isSwitchingChain: boolean;
  canConnect: boolean;
  canManageAccount: boolean;
  connect: () => Promise<void>;
  manageAccount: () => Promise<void>;
  switchChain?: (chainId: number) => Promise<void>;
  sendTransaction?: (
    payload: WalletTxPayload,
  ) => Promise<{ txHash: string; amount?: string }>;
  signTypedData?: (
    payload: WalletEip712Payload,
  ) => Promise<{ signature: string }>;
};

/** @deprecated Use `WalletAdapter` instead. */
export type AomiAdapter = WalletAdapter;

// =============================================================================
// Disconnected default
// =============================================================================

export const DISCONNECTED_ADAPTER: WalletAdapter = {
  identity: {
    kind: "disconnected",
    isConnected: false,
    address: undefined,
    chainId: undefined,
    authProvider: undefined,
    primaryLabel: "Not connected",
    secondaryLabel: undefined,
  },
  isReady: false,
  isSwitchingChain: false,
  canConnect: false,
  canManageAccount: false,
  connect: async () => undefined,
  manageAccount: async () => undefined,
};

// =============================================================================
// Context
// =============================================================================

export const WalletAdapterContext =
  createContext<WalletAdapter | undefined>(undefined);

/** @deprecated Use `WalletAdapterContext` instead. */
export const AomiAdapterContext = WalletAdapterContext;

export function WalletAdapterProvider({
  children,
  value,
}: {
  children: ReactNode;
  value?: WalletAdapter;
}) {
  const inheritedAdapter = useContext(WalletAdapterContext);

  return createElement(
    WalletAdapterContext.Provider,
    { value: value ?? inheritedAdapter },
    children,
  );
}

// =============================================================================
// Hook
// =============================================================================

export function useWalletAdapter(): WalletAdapter {
  const contextAdapter = useContext(WalletAdapterContext);

  return contextAdapter ?? DISCONNECTED_ADAPTER;
}

/** @deprecated Use `useWalletAdapter()` instead. */
export const useAomiAdapter = useWalletAdapter;

"use client";

import { useWalletAdapter } from "./aomi-wallet-adapter";

export type AccountIdentityKind = "disconnected" | "social" | "wallet";

export type AccountIdentity = {
  kind: AccountIdentityKind;
  isConnected: boolean;
  address?: string;
  chainId?: number;
  authProvider?: string;
  primaryLabel: string;
  secondaryLabel?: string;
};

export const DISCONNECTED_ACCOUNT_IDENTITY: AccountIdentity = {
  kind: "disconnected",
  isConnected: false,
  address: undefined,
  chainId: undefined,
  authProvider: undefined,
  primaryLabel: "Not connected",
  secondaryLabel: undefined,
};

export function formatAddress(address?: string): string | undefined {
  if (!address) return undefined;
  return `${address.slice(0, 5)}..${address.slice(-2)}`;
}

export function formatAuthProvider(provider?: string): string | undefined {
  if (!provider) return undefined;

  const labelMap: Record<string, string> = {
    google: "Google",
    github: "GitHub",
    apple: "Apple",
    facebook: "Facebook",
    x: "X",
    discord: "Discord",
    farcaster: "Farcaster",
    telegram: "Telegram",
    email: "Email",
    phone: "Phone",
    wallet: "Wallet",
  };

  return labelMap[provider] ?? provider;
}

export function inferAuthProvider(authMethods: unknown): string | undefined {
  if (!(authMethods instanceof Set) || authMethods.size === 0) return undefined;

  const allowed = new Set([
    "google",
    "github",
    "apple",
    "facebook",
    "x",
    "discord",
    "farcaster",
    "telegram",
    "email",
    "phone",
  ]);

  for (const method of authMethods) {
    if (typeof method !== "string") continue;
    const normalized = method.toLowerCase();
    if (allowed.has(normalized)) return normalized;
  }

  const first = authMethods.values().next().value;
  return typeof first === "string" ? first.toLowerCase() : undefined;
}

export function useAomiAccountIdentity(): AccountIdentity {
  return useWalletAdapter().identity;
}

export const useAccountIdentity = useAomiAccountIdentity;
